import{_ as a,o,c as t,ae as n}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"DMA Compliance for SANs","description":"","frontmatter":{"title":"DMA Compliance for SANs","slug":"dma-compliance-for-sans"},"headers":[],"relativePath":"marketer-hub/dma-compliance-for-sans.md","filePath":"marketer-hub/dma-compliance-for-sans.md"}'),r={name:"marketer-hub/dma-compliance-for-sans.md"};function i(s,e,l,d,c,f){return o(),t("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">ÔÇő</a></h2><p>In 2023, the European Union designated Google as a ÔÇťGatekeeperÔÇŁ under the Digital Marketers Act (DMA). As a result, Google requires that user consent signals be passed along with conversion data for users in the European Economic Area (EEA).</p><p>To support this, we made it possible to pass DMA data to Branch using our SDKs. We then include those consent signals when sending conversion data to your SAN partners.</p><p>By default, this includes all traffic, meaning DMA signals are passed to the ad partner regardless of whether the user is in the EEA or not.</p><h2 id="non-eea-traffic" tabindex="-1">Non-EEA traffic <a class="header-anchor" href="#non-eea-traffic" aria-label="Permalink to &quot;Non-EEA traffic&quot;">ÔÇő</a></h2><p>If you want to drop DMA signals for non-EEA traffic, you can do so for the following SANs:</p><ul><li>Google Ads</li><li>Amazon SAN</li></ul><p>To drop DMA signals for non-EEA traffic for a SAN:</p><ol><li>Go to Branch, and navigate to <strong>Configure &gt; Ad Partners</strong>.</li><li>Search for and select either <strong>Google Ads</strong> or <strong>Amazon SAN</strong>.</li><li>Select the <strong>Event Config</strong> tab for that particular partner.</li><li>Scroll past the event mapping table and find the <strong>Disregard DMA Signals for non EEA traffic</strong> toggle.</li><li>Enable the toggle.</li><li>Select <strong>Save</strong>.</li></ol><p>This toggle is disabled by default. When disabled, Branch passes DMA signals to the ad partner for all traffic regardless of region.</p><h2 id="additional-information" tabindex="-1">Additional information <a class="header-anchor" href="#additional-information" aria-label="Permalink to &quot;Additional information&quot;">ÔÇő</a></h2><p>For more information about sending DMA consent signals using our SDKs, please visit our developer documentation:</p><ul><li><a href="./ios-advanced-features.html#google-dma-compliance">iOS</a></li><li><a href="./android-advanced-features.html#google-dma-compliance">Android</a></li><li><a href="./web-advanced-features.html#google-dma-compliance">Web</a></li><li><a href="./react-native-advanced-features.html#google-dma-compliance">React Native</a></li></ul>',13)])])}const h=a(r,[["render",i]]);export{p as __pageData,h as default};
